"""Ledger model for Ledgerly platform."""
from dataclasses import dataclass, field
from datetime import datetime
from decimal import Decimal
from typing import List, Optional


@dataclass
class LedgerEntry:
    """A single entry in the internal ledger."""
    entry_id: str
    merchant_id: str
    transaction_id: str
    amount: Decimal
    fee_amount: Decimal
    net_amount: Decimal  # amount - fee_amount
    entry_date: str  # YYYY-MM-DD
    currency: str = "USD"
    reconciled: bool = False

    def __post_init__(self):
        for attr in ('amount', 'fee_amount', 'net_amount'):
            val = getattr(self, attr)
            if not isinstance(val, Decimal):
                setattr(self, attr, Decimal(str(val)))


@dataclass
class DailyLedgerSummary:
    """Aggregated ledger data for a merchant on a given date."""
    merchant_id: str
    date: str  # YYYY-MM-DD
    entries: List[LedgerEntry] = field(default_factory=list)

    @property
    def total_amount(self) -> Decimal:
        """Sum of all transaction amounts."""
        return sum((e.amount for e in self.entries), Decimal("0.00"))

    @property
    def total_fees(self) -> Decimal:
        """Sum of all fee amounts."""
        return sum((e.fee_amount for e in self.entries), Decimal("0.00"))

    @property
    def total_net(self) -> Decimal:
        """Sum of all net amounts (after fees)."""
        return sum((e.net_amount for e in self.entries), Decimal("0.00"))

    @property
    def transaction_count(self) -> int:
        return len(self.entries)

"""Date utilities for Ledgerly platform."""
from datetime import datetime, date, timedelta
from typing import List

DATE_FORMAT = "%Y-%m-%d"


def parse_date(date_str: str) -> date:
    """Parse a date string in YYYY-MM-DD format."""
    return datetime.strptime(date_str, DATE_FORMAT).date()


def format_date(d: date) -> str:
    """Format a date as YYYY-MM-DD string."""
    return d.strftime(DATE_FORMAT)


def get_date_range(start: str, end: str) -> List[str]:
    """Get a list of date strings between start and end (inclusive)."""
    start_date = parse_date(start)
    end_date = parse_date(end)
    dates = []
    current = start_date
    while current <= end_date:
        dates.append(format_date(current))
        current += timedelta(days=1)
    return dates
